{{
(() => {

  const origen = Number(selMoneda_AV.selectedOptionValue);
  const destino = Number(selOtraMonedaCodigoAV.selectedOptionValue);

  const monto = Number((inpTotalDesembolsoAV.text || "0").replace(/,/g, ""));
  const tasa = Number((inpTasaOtraMonedaAV.text || "0").replace(/,/g, ""));

  if (!origen || !destino || tasa <= 0 || origen === destino) {
    return "";
  }

  let resultado = null;

  // DOP -> USD/EUR
  if (origen === 1 && (destino === 2 || destino === 3))
    resultado = monto / tasa;

  // USD -> DOP
  else if (origen === 2 && destino === 1)
    resultado = monto * tasa;

  // USD -> EUR
  else if (origen === 2 && destino === 3)
    resultado = monto / tasa;

  // EUR -> DOP
  else if (origen === 3 && destino === 1)
    resultado = monto * tasa;

  // EUR -> USD
  else if (origen === 3 && destino === 2)
    resultado = monto * tasa;

  return resultado == null
    ? ""
    : resultado.toLocaleString("en-US", {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      });

})()
}}
